import React, { useEffect, useState } from "react";
import axios from "axios";
import "../index.css";

const OrdersPage = () => {
  const [orders, setOrders] = useState([]);

  const fetchOrders = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/orders");
      setOrders(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    fetchOrders();
  }, []);

  const handleCancelOrder = async (orderId) => {
    const reason = prompt("Enter reason for cancelling the order:");
    if (!reason) return alert("Cancellation reason required");

    try {
      await axios.put(`http://localhost:5000/api/orders/${orderId}/cancel`, { cancelReason: reason });
      alert("Order cancelled successfully");
      fetchOrders();
    } catch (err) {
      console.error(err);
      alert("Failed to cancel order");
    }
  };

  const handleCancelItem = async (orderId, itemId) => {
    const reason = prompt("Enter reason for cancelling this item:");
    if (!reason) return alert("Cancellation reason required");

    try {
      await axios.put(`http://localhost:5000/api/orders/${orderId}/cancel-item/${itemId}`, { cancelReason: reason });
      alert("Item cancelled successfully");
      fetchOrders();
    } catch (err) {
      console.error(err);
      alert("Failed to cancel item");
    }
  };

  return (
    <div className="orders-page">
      <h2>Your Orders</h2>
      {orders.length === 0 ? (
        <p>No orders found.</p>
      ) : (
        orders.slice().reverse().map(order => (
          <div key={order._id} className="order-card">
            <div className="order-header">
              <span>Order #{order._id}</span>
              <span className={`order-status ${order.status === "Cancelled" ? "cancelled" : "placed"}`}>
                {order.status}
              </span>
            </div>
            <p>📅 {order.date}</p>

            <div className="order-items">
              {order.items.map(item => (
                <div key={item._id} className="order-item">
                  <img src={item.image || "https://via.placeholder.com/80"} alt={item.name} />
                  <div>
                    <h4>{item.name}</h4>
                    <p>₹{item.price} × {item.quantity}</p>
                    {item.status !== "Cancelled" && (
                      <button onClick={() => handleCancelItem(order._id, item._id)}>Cancel Item</button>
                    )}
                    {item.status === "Cancelled" && <p>Cancelled</p>}
                  </div>
                </div>
              ))}
            </div>

            <div className="order-summary">
              <p><strong>Name:</strong> {order.name}</p>
              <p><strong>Mobile:</strong> {order.mobile}</p>
              <p><strong>Address:</strong> {order.address}</p>
              <p><strong>Payment:</strong> {order.payment}</p>
              <p><strong>Total:</strong> ₹{order.total}</p>
            </div>

            {order.status !== "Cancelled" && (
              <button onClick={() => handleCancelOrder(order._id)}>Cancel Order</button>
            )}
          </div>
        ))
      )}
    </div>
  );
};

export default OrdersPage;
